-- Verification
SELECT
  COUNT(*) FILTER (WHERE hrc_ceiling_reference IS NOT NULL) AS rows_with_ceiling,
  ROUND(AVG(hrc_ceiling_reference)::numeric, 3) AS avg_hrc_ceiling,
  ROUND(AVG(hrc_ceiling_reference - hrc_score)::numeric, 3) AS avg_gap_to_ceiling
FROM hrc_tiles
WHERE longitude BETWEEN -123.0 AND -121.2
  AND latitude BETWEEN 37.0 AND 38.6;
